def _raster_from_pillow(data: bytes) -> Raster:
    with Image.open(BytesIO(data)) as image:
        if getattr(image, "n_frames", 1) > 1:
            image.seek(0)
        rgb = image.convert("RGB")
        return Raster(rgb.width, rgb.height, 3, bytearray(rgb.tobytes()))
